
"use client";

import { useState, useMemo, useEffect } from 'react';
import { useSearchParams } from 'next/navigation';
import { SiteHeader } from "@/components/SiteHeader";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";
import { PlusCircle, Trash2, ArrowLeft } from 'lucide-react';
import Link from 'next/link';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

// Mock data, in a real app this would come from a database
// const allVendors: { id: string, name: string, description: string }[] = [
// ];

const initialMenus: { [key: string]: MenuItem[] } = {
};

type MenuItem = {
  id: string;
  name: string;
  price: number;
};

export default function MenuAdminPage({ params }: { params: { vendorId: string } }) {
  const { vendorId } = params;
  const searchParams = useSearchParams();
  const vendorName = searchParams.get('name') || '店家';
  const { toast } = useToast();

  const [menu, setMenu] = useState<MenuItem[]>(initialMenus[vendorId as keyof typeof initialMenus] || []);
  const [newItemName, setNewItemName] = useState('');
  const [newItemPrice, setNewItemPrice] = useState('');

  const handleAddItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemName.trim() || !newItemPrice.trim()) {
      toast({ variant: "destructive", title: "請輸入品項名稱和價格" });
      return;
    }
    
    const price = parseInt(newItemPrice, 10);
    if (isNaN(price) || price <= 0) {
      toast({ variant: "destructive", title: "請輸入有效的價格" });
      return;
    }

    const newItem = {
      id: `${vendorId}-${Date.now()}`,
      name: newItemName,
      price: price,
    };

    // In a real app, this would be an API call
    setMenu([...menu, newItem]);
    setNewItemName('');
    setNewItemPrice('');

    toast({ title: "品項已新增 (模擬)", description: "此為模擬操作，尚未寫入 Google Sheet。" });
  };
  
  const handleDeleteItem = (itemId: string, itemName: string) => {
    // In a real app, this would be an API call
    setMenu(menu.filter(item => item.id !== itemId));
    toast({ title: "品項已刪除 (模擬)", description: `${itemName} 已從菜單移除。此為模擬操作，尚未寫入 Google Sheet。`});
  };

  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <div className="mb-6">
            <Link href="/admin" className="flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground">
                <ArrowLeft className="h-4 w-4" />
                返回店家列表
            </Link>
        </div>
        <h1 className="font-headline text-3xl font-bold mb-2">編輯菜單：{decodeURIComponent(vendorName)}</h1>
        <p className="text-muted-foreground mb-6">管理 {decodeURIComponent(vendorName)} 的菜單品項。</p>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Add New Item */}
          <section>
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <PlusCircle className="h-6 w-6" />
                  <span>新增菜單品項</span>
                </CardTitle>
                <CardDescription>為 {decodeURIComponent(vendorName)} 加入新的餐點。</CardDescription>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleAddItem} className="space-y-4">
                  <Input 
                    placeholder="品項名稱 (例如: 雞腿飯)" 
                    value={newItemName}
                    onChange={(e) => setNewItemName(e.target.value)}
                  />
                  <Input 
                    type="number"
                    placeholder="價格" 
                    value={newItemPrice}
                    onChange={(e) => setNewItemPrice(e.target.value)}
                  />
                  <Button type="submit" className="w-full">新增品項</Button>
                </form>
              </CardContent>
            </Card>
          </section>
          
          {/* Menu Item List */}
          <section>
            <Card>
              <CardHeader>
                <CardTitle>現有品項</CardTitle>
                <CardDescription>管理目前的菜單品項。</CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {menu.length > 0 ? (
                  menu.map(item => (
                    <Card key={item.id} className="p-3 flex justify-between items-center">
                      <div>
                        <p className="font-semibold">{item.name}</p>
                        <p className="text-sm text-muted-foreground">${item.price}</p>
                      </div>
                      <AlertDialog>
                          <AlertDialogTrigger asChild>
                              <Button variant="ghost" size="icon" aria-label={`刪除 ${item.name}`}>
                                  <Trash2 className="h-4 w-4 text-destructive" />
                              </Button>
                          </AlertDialogTrigger>
                          <AlertDialogContent>
                              <AlertDialogHeader>
                                  <AlertDialogTitle>確定要刪除品項嗎？</AlertDialogTitle>
                                  <AlertDialogDescription>
                                      此動作無法復原。這將會永久刪除菜單品項「{item.name}」。
                                  </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                  <AlertDialogCancel>取消</AlertDialogCancel>
                                  <AlertDialogAction onClick={() => handleDeleteItem(item.id, item.name)}>確定刪除</AlertDialogAction>
                              </AlertDialogFooter>
                          </AlertDialogContent>
                      </AlertDialog>
                    </Card>
                  ))
                ) : (
                  <p className="text-sm text-center text-muted-foreground py-4">這個店家還沒有任何菜單品項。</p>
                )}
              </CardContent>
            </Card>
          </section>
        </div>
      </main>
    </div>
  );
}
